/* Aula 22 — modelJs: Form com validação + UX mínima */

const form = document.querySelector('#form');
const nomeInput = document.querySelector('#nome');
const emailInput = document.querySelector('#email');
const senhaInput = document.querySelector('#senha');

const erroNome = document.querySelector('#erro-nome');
const erroEmail = document.querySelector('#erro-email');
const erroSenha = document.querySelector('#erro-senha');
const msg = document.querySelector('#msg');

function setErro(input, erroEl, mensagem) {
  erroEl.textContent = mensagem;
  input.classList.add('input-error');
  input.classList.remove('input-success');
}

function setOk(input, erroEl) {
  erroEl.textContent = '';
  input.classList.remove('input-error');
  input.classList.add('input-success');
}

function validarNome(nome) {
  if (nome.length === 0) return 'Nome é obrigatório';
  if (nome.length < 2) return 'Nome muito curto';
  return '';
}

function validarEmail(email) {
  if (email.length === 0) return 'Email é obrigatório';
  if (!email.includes('@') || !email.includes('.')) return 'Email inválido';
  return '';
}

function validarSenha(senha) {
  if (senha.length === 0) return 'Senha é obrigatória';
  if (senha.length < 8) return 'Senha precisa ter 8+ caracteres';
  return '';
}

function validarCampo(input, erroEl, fnValidar) {
  const valor = input.value.trim();
  const erro = fnValidar(valor);
  if (erro) {
    setErro(input, erroEl, erro);
    return false;
  }
  setOk(input, erroEl);
  return true;
}

if (form && nomeInput && emailInput && senhaInput && erroNome && erroEmail && erroSenha && msg) {
  // validação ao digitar
  nomeInput.addEventListener('input', () => validarCampo(nomeInput, erroNome, validarNome));
  emailInput.addEventListener('input', () => validarCampo(emailInput, erroEmail, validarEmail));
  senhaInput.addEventListener('input', () => validarCampo(senhaInput, erroSenha, validarSenha));

  // submit
  form.addEventListener('submit', (e) => {
    e.preventDefault();
    msg.textContent = '';

    const okNome = validarCampo(nomeInput, erroNome, validarNome);
    const okEmail = validarCampo(emailInput, erroEmail, validarEmail);
    const okSenha = validarCampo(senhaInput, erroSenha, validarSenha);

    if (!okNome || !okEmail || !okSenha) {
      msg.textContent = 'Corrija os campos acima.';
      return;
    }

    msg.textContent = 'Login ok!';
    form.reset();

    // limpar estados visuais após reset
    [nomeInput, emailInput, senhaInput].forEach((i) => {
      i.classList.remove('input-error');
      i.classList.remove('input-success');
    });
  });
}
